        int currentNumber = start + i;

        if (currentNumber % 3 == 0 && currentNumber % 5 == 0) {
            result[i] = "FizzBuzz";
        } else if (currentNumber % 3 == 0) {
            result[i] = "Fizz";
        } else if (currentNumber % 5 == 0) {
            result[i] = "Buzz";
        } else {
            result[i] = String.valueOf(currentNumber);
        }
    }

    return result;
}

